syft <compiled-package.tar.gz> -o cyclonedx-json | grype -o json | jq '[.matches[] | {id: .vulnerability.id, related_cves: [.relatedVulnerabilities[]?.id] | join(", "), pkg: .artifact.name, ver: .artifact.version, pkg_type: .artifact.type, sev: .vulnerability.severity, cvss_score: .vulnerability.cvss[0]?.metrics?.baseScore, cvss_vector: .vulnerability.cvss[0]?.vector, fix_state: .vulnerability.fix.state, desc: .vulnerability.description}]' > minimal_triage_<package_name>.json